#include <stdlib.h>
#include <string.h>
#include <math.h>
#include "cJSON.h"

/* Forward declarations from lodepng */
unsigned lodepng_decode32_file(unsigned char** out, unsigned* w, unsigned* h, const char* filename);

#define MAX_WEIGHTS 100000

typedef struct {
    float *weights;
    float *bias;
    int in_features;
    int out_features;
} LinearLayer;

typedef struct {
    LinearLayer *layers;
    int num_layers;
    int input_dim;
    int hidden_dim;
    int num_classes;
} Model;

static void parse_array_float(const cJSON *arr, float *out, int n) {
    for (int i = 0; i < n; i++) {
        out[i] = (float)cJSON_GetArrayItem(arr, i)->valuedouble;
    }
}

static Model load_model(const char *filename) {
    Model model = {0};
    FILE *f = fopen(filename, "r");
    if (!f) {
        fprintf(stderr, "Cannot open %s\n", filename);
        exit(1);
    }
    fseek(f, 0, SEEK_END);
    long fsize = ftell(f);
    fseek(f, 0, SEEK_SET);
    char *json_str = malloc(fsize + 1);
    fread(json_str, 1, fsize, f);
    fclose(f);
    json_str[fsize] = '\0';

    cJSON *root = cJSON_Parse(json_str);
    free(json_str);

    model.input_dim = cJSON_GetObjectItem(root, "input_dim")->valueint;
    model.hidden_dim = cJSON_GetObjectItem(root, "hidden_dim")->valueint;
    model.num_classes = cJSON_GetObjectItem(root, "num_classes")->valueint;

    int num_layers = cJSON_GetArrayItem(cJSON_GetObjectItem(root, "layers"), 0) ? 
                     cJSON_GetArraySize(cJSON_GetObjectItem(root, "layers")) : 0;
    model.num_layers = num_layers;
    model.layers = calloc(num_layers, sizeof(LinearLayer));

    int layer_idx = 0;
    for (int i = 0; i < num_layers; i++) {
        cJSON *layer = cJSON_GetArrayItem(cJSON_GetObjectItem(root, "layers"), i);
        char *type = cJSON_GetObjectItem(layer, "type")->valuestring;

        if (strcmp(type, "linear") == 0) {
            LinearLayer *l = &model.layers[layer_idx];
            l->in_features = cJSON_GetObjectItem(layer, "in_features")->valueint;
            l->out_features = cJSON_GetObjectItem(layer, "out_features")->valueint;

            int w_size = l->in_features * l->out_features;
            int b_size = l->out_features;

            l->weights = malloc(w_size * sizeof(float));
            l->bias = malloc(b_size * sizeof(float));

            parse_array_float(cJSON_GetObjectItem(layer, "weights"), l->weights, w_size);
            parse_array_float(cJSON_GetObjectItem(layer, "bias"), l->bias, b_size);

            layer_idx++;
        }
    }

    cJSON_Delete(root);
    return model;
}

static void free_model(Model *model) {
    for (int i = 0; i < model->num_layers; i++) {
        free(model->layers[i].weights);
        free(model->layers[i].bias);
    }
    free(model->layers);
}

/* Forward pass: matrix multiply + bias + ReLU */
static void forward_linear(const LinearLayer *layer, const float *input, float *output) {
    for (int j = 0; j < layer->out_features; j++) {
        float sum = layer->bias[j];
        for (int i = 0; i < layer->in_features; i++) {
            sum += input[i] * layer->weights[i * layer->out_features + j];
        }
        output[j] = sum;
    }
}

static void forward_relu(const float *input, float *output, int n) {
    for (int i = 0; i < n; i++) {
        output[i] = fmaxf(input[i], 0.0f);
    }
}

static int predict(Model *model, const float *input) {
    /* Allocate activations */
    float *current = malloc(model->input_dim * sizeof(float));
    memcpy(current, input, model->input_dim * sizeof(float));

    for (int i = 0; i < model->num_layers; i++) {
        LinearLayer *layer = &model->layers[i];
        float *next = malloc(layer->out_features * sizeof(float));

        forward_linear(layer, current, next);

        /* Check if next layer is ReLU (odd-indexed non-linear layers) */
        int is_relu = 0;
        for (int j = i + 1; j < model->num_layers; j++) {
            if (model->layers[j].in_features == 0) {
                is_relu = 1;
                break;
            }
        }

        if (is_relu) {
            forward_relu(next, next, layer->out_features);
        }

        free(current);
        current = next;
    }

    /* Find argmax */
    int best = 0;
    for (int i = 1; i < model->num_classes; i++) {
        if (current[i] > current[best]) {
            best = i;
        }
    }

    free(current);
    return best;
}

static float *load_image(const char *filename, int expected_size) {
    unsigned char *image = NULL;
    unsigned width, height;
    unsigned err = lodepng_decode32_file(&image, &width, &height, filename);
    if (err) {
        fprintf(stderr, "PNG decode error: %s\n", lodepng_error_text(err));
        exit(1);
    }

    /* Resize to expected_size x expected_size and normalize */
    int size = (int)sqrtf((float)expected_size);
    float *input = malloc(expected_size * sizeof(float));

    for (int y = 0; y < size; y++) {
        for (int x = 0; x < size; x++) {
            /* Map to nearest pixel in original image */
            int ox = (x * width) / size;
            int oy = (y * height) / size;
            int idx = (oy * width + ox) * 4;
            /* Grayscale and normalize to [0,1] */
            float val = (255.0f - image[idx]) / 255.0f;
            input[y * size + x] = val;
        }
    }

    free(image);
    return input;
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s weights.json image.png\n", argv[0]);
        return 1;
    }

    Model model = load_model(argv[1]);
    float *input = load_image(argv[2], model.input_dim);

    int prediction = predict(&model, input);
    printf("%d\n", prediction);

    free(input);
    free_model(&model);
    return 0;
}
